#include<bits/stdc++.h>
using namespace std;

void solve() {
	long long ans = 0;
	long long a0, a1, b0, b1;
	cin >> a0 >> a1 >> b0 >> b1;
	for (int x = 1; x * x <= b1; x++) {
		if (b1 % x == 0) {
			if (x % a1 == 0 && __gcd(x / a1, a0 / a1) == 1 && __gcd(b1 / b0, b1 / x) == 1) ans++;
			int x2 = b1 / x;
			if (x2 != x) {
				if (x2 % a1 == 0 && __gcd(x2 / a1, a0 / a1) == 1 && __gcd(b1 / b0, b1 / x2) == 1) ans++;
			}
		}
	}
	cout << ans<<"\n";
	return;
}
int main() {
	int t;
	cin >> t;
	while (t--) solve();
}
